#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to find prime factors
void primeFactors(int n, int *factors, int *powers) {
    int i = 2;
    while (i * i <= n) {
        if (n % i == 0) {
            factors[0] = i;
            powers[0] = 0;
            while (n % i == 0) {
                n /= i;
                powers[0]++;
            }
        }
        i++;
    }
    if (n > 1) {
        factors[1] = n;
        powers[1] = 1;
    }
}

int main() {
    int T;
    scanf("%d", &T);
