        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int maxGCD = 1;
        for (int i = 2; i <= sqrt(max(A, A + N)); i++) {
            int minPower = INT_MAX;
            for (int j = 0; j < N; j++) {
                int power = 0;
                while (A[j] % i == 0) {
                    A[j] /= i;
                    power++;
                }
                minPower = min(minPower, power);
            }
            for (int j = 0; j < minPower; j++) {
                maxGCD *= i;
            }
        }
        printf("%d\n", maxGCD);
    }
    return 0;
}

