// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int maxGCD = 1;
            for (int i = 2; i <= Math.sqrt(max(A)); i++) {
                int minPower = Integer.MAX_VALUE;
                for (int j = 0; j < N; j++) {
                    int power = 0;
                    while (A[j] % i == 0) {
                        A[j] /= i;
                        power++;
                    }
                    minPower = Math.min(minPower, power);
                }
                for (int j = 0; j < minPower; j++) {
                    maxGCD *= i;
                }
            }
            System.out.println(maxGCD);
        }
    }
    public static int max(int[] arr) {
        int max = arr[0];
        for (int i = 1; i < arr.length; i++) {
            if (arr[i] > max) {
                max = arr[i];
            }
        }
        return max;
    }
}

